arguments.argument:
if global.gamePaused=false
{
  if laserUp=1
  {
    laserScl+=0.01
    if laserScl>=0.15 {laserUp=0}
  }
  else
  {
    laserScl-=0.01
    if laserScl<=0 {laserUp=1}
  }
  
  moveDelay-=1
  if moveDelay<=0
  {
    if laserProg=0
    {
      y+=moveSpd
      if y>=288
      {
        laserProg=1
      }
    }
    else if laserProg=1
    {
      image_alpha-=0.1
      if image_alpha<=0.5 {bCanDealDamage=0}
      if image_alpha<=0 {instance_destroy()}
    }
  }
}
